import React, { useEffect, useState, useContext } from "react";
import { AuthContext } from "../../context/AuthContext";
import axios from "axios";

const AdminNotifications = () => {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user } = useContext(AuthContext);

  useEffect(() => {
    fetchNotifications();
  }, []);

  const fetchNotifications = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/notifications", {
        headers: { Authorization: `Bearer ${user.token}` },
      });

      setData(res.data.data);
    } catch (err) {
      console.error("❌ Load notifications error:", err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      {/* HEADER PAGE */}
      <div className="flex justify-between items-center mb-10 -ml-2">
        <h2 className="text-2xl font-semibold flex items-center gap-2">
          <span className="text-[#e06c7f]">🔔</span> THÔNG BÁO
        </h2>
      </div>

      {/* LIST */}
      {loading ? (
        <div className="flex justify-center py-10">
          <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-[#e06c7f]"></div>
        </div>
      ) : data.length === 0 ? (
        <div className="bg-[#faf8f6] text-[#8b5e3c] border border-[#f1e4da] rounded-lg p-8 text-center">
          Không có thông báo nào 🌸
        </div>
      ) : (
        <div className="bg-white border border-[#f1e4da] rounded-lg shadow-sm">
          <ul className="divide-y divide-[#f1e4da]">
            {data.map((n) => (
              <li key={n._id} className="p-4 hover:bg-[#fff4f7] transition">
                <p className="font-semibold text-[#3e2f2f]">{n.message}</p>
                <p className="text-xs text-gray-500 mt-1">
                  {new Date(n.createdAt).toLocaleString("vi-VN")}
                </p>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
};

export default AdminNotifications;
